"""
MKT Original Commentary — Revelation chapters 21–22
Run: python3 scripts/zc-original-revelation-21-22-full.py

Source data used:
- data/interlinear/revelation.json
- data/translation/glossary-greek.json (kainos, skene, naos, plateia, exousia)
- data/translation/draft/mediating/revelation.json (MKT text for quoting)
- Existing scripts: zc-original-revelation-1-5.py (style and terminology baseline)

Key decisions:
- Transliterated Greek in <strong> tags, following established zc-original-revelation-1-5 style
- kainos (qualitatively new) vs. neos (chronologically new) — significant throughout ch. 21
- Single throne of God and the Lamb (22:1, 3) carries Christological weight; noted consistently
- The absence of a temple (21:22) treated as a positive theological statement, not mere absence
- ekō hoi kynes (22:15) — 'dogs' as ritual exclusion category, not a slur; see Jewish purity context
- Textual variant at 22:14: 'wash their robes' vs. 'do his commandments' — UBS/NA28 prefers former
- Three erchomai tachy sayings (22:7, 12, 20) treated as a rhetorical triad, noted at each
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

REVELATION = {
  "21": {
    "1": '<p><strong>kainos ouranos kai kainē gē</strong> — <em>kainos</em> (qualitatively new, not chronologically new; contrast <em>neos</em>) is the word Revelation uses throughout the new-creation vision. The distinction matters: this is not a renovated cosmos but a new one of a different order altogether. The same word appears in 2 Cor 5:17 (new creation) and Isa 65:17 LXX.</p><p><strong>ho gar prōtos ouranos kai hē prōtē gē apēlthan</strong>: the first heaven and earth <em>apēlthan</em> (went away, departed) — the same verb used in 21:4 for the old order passing. The absence of the sea (<em>hē thalassa ouk estin eti</em>) is significant: in ANE cosmology and in OT imagery, the sea represents primordial chaos (Gen 1:2), the domain of the beast (13:1), and the barrier that separates. Its disappearance signals the end of chaos, threat, and separation.</p>',

    "2": '<p><strong>tēn polin tēn hagian Ierousalēm kainēn eidon katabainousan ek tou ouranou apo tou theou</strong>: the city is <em>katabainousan</em> (descending, present participle) — an ongoing, visionary descent. The new Jerusalem is not a human achievement ascending from below but a divine gift descending from above. The grammar signals its character: this city originates with God, not with human civilization or religion.</p><p><strong>hētoimasmenēn hōs nymphen kekosmēmenēn tō andri autēs</strong>: prepared as a bride adorned for her husband. The bride metaphor activates the OT covenant-marriage imagery (Isa 61:10; 62:5; Jer 2:2; Ezek 16) where YHWH is husband and Israel is bride. The new Jerusalem as the bride of the Lamb (v. 9) is the eschatological fulfillment of the entire covenant relationship: the People of God perfected and united with the God who covenanted with them.</p>',

    "4": '<p><strong>kai exaleipsei pan dakryon ek tōn ophthalmōn autōn</strong>: <em>exaleipsei</em> (will wipe out, erase completely; future active) — the same root is used in Acts 3:19 for the erasure of sins. God erases tears as decisively as he forgives guilt: both are obliterated, not merely set aside. The promise quotes Isa 25:8 (YHWH will swallow up death and wipe away tears from all faces) and reverses the mourning of Isa 65:19.</p><p><strong>ho thanatos ouk estai eti</strong> — <em>ouk ... eti</em> (no longer, not any more): categorical negation with emphasis. Death itself ceases; this is not survival of death but its abolition. <em>Ta prōta apēlthan</em> (the first things have gone away) uses the same <em>apēlthan</em> as v. 1 — the old order departs as a unified whole: death, grief, pain, the sea, the first heaven and earth all belong to the old order that is now gone.</p>',

    "5": '<p><strong>idou kaina poiō panta</strong>: <em>kaina</em> (qualitatively new) with the present tense <em>poiō</em> (I am making) — the new creation is announced as a present act of the divine will, not a future plan. The one speaking is seated on the throne: in Revelation\'s theology the throne is shared between God the Father and the Lamb (22:1, 3), so the speaker carries the full divine authority that opened the cosmos in Genesis.</p><p><strong>hoti houtoi hoi logoi pistoi kai alēthinoi eisin</strong>: the authentication formula (repeated at 22:6; 19:9) — these words are <em>pistoi kai alēthinoi</em> (faithful and true), the divine self-description from Rev 3:14 and 19:11. The words are vouched for by their source: the one who is Faithful-and-True declares that these words share his own character.</p>',

    "6": '<p><strong>gegonen</strong>: the perfect active of <em>ginomai</em> — "It has happened and stands accomplished." The same verb Jesus uses on the cross (<em>tetelestai</em> in John, but here using <em>ginomai</em>) signals the consummation of redemptive history. The use of the perfect (not the aorist) is precise: the new creation is not just completed but completed with permanent effect.</p><p><strong>ego eimi to Alpha kai to Omega, hē archē kai to telos</strong>: the Alpha-Omega formula here is attributed to God the Father (as in 1:8); in 22:13 the same three-part formula (Alpha/Omega + First/Last + Beginning/End) is applied to Christ — the shared title making the Christological identification explicit. <em>Hē archē kai to telos</em> (the Beginning and the End) is new in v. 6, expanding the pair from ch. 1; all three formulas converge in 22:13.</p><p><strong>tō dipsōnti dōsō ek tēs pēgēs tou hydatos tēs zōēs dōrean</strong>: <em>dōrean</em> (freely, as gift, at no cost) — this adverb characterizes the gift as grace: the water of life is not earned or purchased. The thirst imagery activates Isa 55:1 (come to the waters, you who are thirsty; come and buy without money) and John 4:14 (the water I give will become a spring welling up to eternal life).</p>',

    "7": '<p><strong>ho nikōn klēronomēsei tauta</strong>: <em>ho nikōn</em> (the one who conquers, present participle — continuous overcoming) echoes the promise to the <em>nikōn</em> in each of the seven letters (chs. 2–3). <em>Klēronomēsei</em> (will inherit) — inheritance language recalls the covenant promise to Abraham (Gen 12; 15; 17) and the promised land; here it is eschatological: the whole new creation is the inheritance of those who endure.</p><p><strong>kai esomai autō theos kai autos estai moi [ho] huios</strong>: the covenant formula applied universally. 2 Sam 7:14 speaks of the Davidic king ("I will be his father and he will be my son"); Ps 89:26-27 applies it to the one who cries "My Father." Revelation applies this father-son adoption language to every overcomer — the promises made to the messianic king are extended to all who are in Christ.</p>',

    "8": '<p><strong>hoi deiloi</strong>: the cowardly/faithless-under-pressure — placed first in the exclusion list, ahead of murderers and sorcerers. <em>Deilos</em> is used in Mark 4:40 when Jesus rebukes the disciples\' fear in the storm ("Why are you so afraid? Have you no faith?"). In Revelation\'s context of Roman persecution, the cowardly are those who apostatize to avoid suffering — a more acute pastoral concern than abstract vices.</p><p><strong>ho thanatos ho deuteros</strong>: the second death. Revelation defines it as the lake of fire (20:14). The "second death" is a concept found in Targum literature (Tg. Deut 33:6; Tg. Isa 22:14; 65:6) where it means permanent, irreversible exclusion from God. Revelation adopts and crystalizes the term. The first death (biological) may claim the faithful; the second death (eternal exclusion) cannot (2:11; 20:6).</p>',

    "9": '<p><strong>deuro, deixō soi tēn nymphen tēn gynaika tou arniou</strong>: "Come, I will show you the bride, the wife of the Lamb." This invitation deliberately mirrors 17:1 where the same angel invites John: "Come, I will show you the judgment of the great prostitute." The two visions are paired: Babylon the harlot (ch. 17–18) vs. Jerusalem the bride (ch. 21). The angel offers the same transportation to see radically different destinations — judgment and redemption shown by the same guide.</p>',

    "10": '<p><strong>kai apēnegken me en pneumati epi oros mega kai hypsēlon</strong>: transported <em>en pneumati</em> (in the Spirit) to a great and high mountain. This visionary transportation echoes Ezek 40:1-2 precisely: the Spirit brings Ezekiel to "a very high mountain" to see the new temple city. John\'s new Jerusalem vision is the fulfillment of Ezekiel\'s vision — the mountain-top perspective enabling the Seer to receive what Ezekiel received as promise. The Spirit-transportation also echoes Ezek 3:14; 8:3; 11:1, 24.</p>',

    "11": '<p><strong>echousan tēn doxan tou theou</strong>: "having the glory of God" — the Shekinah, the divine radiance that filled the tabernacle (Exod 40:34-35) and the Solomonic temple (1 Kgs 8:10-11), and that Ezekiel saw depart from the temple at the Babylonian conquest (Ezek 10:18-19; 11:22-23), now permanently dwelling in the new Jerusalem. The city does not merely reflect glory — it <em>has</em> it as its intrinsic characteristic.</p><p><strong>hō phōstēr autēs homoios lithō timiōtatō hōs lithō iaspidi krystalloeidei</strong>: the city\'s radiance compared to jasper clear as crystal. Jasper (<em>iaspis</em>) is used both for the appearance of the one on the throne (4:3) and now for the city that houses his presence — the city\'s appearance mirrors the divine glory itself. The precious stones throughout vv. 19-21 echo Ezek 28:13 (the king of Tyre adorned with precious stones in Eden) and the high-priestly breastplate (Exod 28:17-20).</p>',

    "12": '<p><strong>echousa teicho mega kai hypsēlon echousa pylōnas dōdeka kai epi tois pylōsin angelous dōdeka kai onomata epigegrammena ha estin [ta onomata] tōn dōdeka phylōn huiōn Israēl</strong>: the wall with twelve gates and twelve angels, the gates bearing the names of the twelve tribes. Ezek 48:31-35 already assigned the twelve gates of the ideal city to the twelve tribes. The angels at the gates function as guardians — but also as witnesses to the access structure: the new Jerusalem is entered through the covenant people (the tribes) who represent the full scope of Israel\'s election.</p>',

    "13": '<p><strong>apo anatolēs pylōnes treis kai apo borra pylōnes treis kai apo notou pylōnes treis kai apo dysmōn pylōnes treis</strong>: three gates on each of the four sides, facing all compass points. This orientation mirrors both Ezek 48:31-34 (same arrangement for the ideal city\'s gates) and the arrangement of the tribes around the tabernacle in the wilderness (Num 2). The four-directional opening signals the universal accessibility of the new Jerusalem: approach from every direction is possible. No gate is the "back entrance."</p>',

    "14": '<p><strong>kai to teicho tēs poleōs echōn thremeliou dōdeka kai ep autōn dōdeka onomata tōn dōdeka apostolōn tou arniou</strong>: twelve foundations inscribed with the names of the twelve apostles. Gates named for the tribes (OT); foundations named for the apostles (NT). The city is built on both testimonies — the continuity of OT and NT revelation architecturally expressed. Eph 2:20 speaks of the church "built on the foundation of the apostles and prophets"; here that Pauline metaphor becomes literal architecture in the new Jerusalem. The apostles are apostles <em>tou Arniou</em> (of the Lamb) — their authority derives from and belongs to the Lamb.</p>',

    "15": '<p><strong>ho lalōn met emou eichen metron kalamon chrysoun</strong>: a golden measuring rod. Measuring in apocalyptic literature signals divine claiming and protection (Ezek 40; Zech 2:1-5; Rev 11:1-2). That the measuring rod is <em>chrysoun</em> (golden) matches the city\'s materials — the instrument of measurement is made of what the city is made of, signaling that the city fully meets the divine standard. The angel\'s measurement is an act of divine affirmation: this city is exactly what God intends.</p>',

    "16": '<p><strong>kai hē polis tetragonos keitai kai to mēkos autēs hoson [kai] to platos</strong>: the city is <em>tetragonos</em> (four-cornered, square — or by extension, cubic) — equal in length, width, and height. 12,000 stadia in each dimension. The cubic shape recalls the Holy of Holies in Solomon\'s temple (1 Kgs 6:20: twenty cubits in length, width, and height — a perfect cube). The entire new Jerusalem is the Holy of Holies — the inner sanctuary of divine presence expanded to cosmic proportions. What was restricted to the high priest once a year is now the entire dwelling of the redeemed.</p>',

    "17": '<p><strong>kai emethrēsen to teicho autou hekatōn tessarakonta tessarōn pēchōn metrou anthrōpou ho estin angelou</strong>: 144 cubits (= 12 × 12) for the wall — another multiple of 12, the number of completeness in Revelation (twelve tribes, twelve apostles, 144,000). The curious note that the human measurement is also the angel\'s measurement (<em>metrou anthrōpou ho estin angelou</em>) may signal the unity of human and angelic existence in the new creation: the customary distinction between earthly and heavenly scales no longer applies.</p>',

    "18": '<p><strong>kai hē endōmēsis tou teichous autēs iaspis kai hē polis chrysos katharos homoios hyalō katharō</strong>: <em>endōmēsis</em> is a rare word (possibly a hapax in biblical Greek) for "building material" or "construction." Pure gold transparent as glass is physically impossible — gold is opaque. The description signals that the new creation\'s materials exceed what the old physics permits: this is not renovated matter but transfigured matter, the stuff of a world where divine glory permeates everything. The transparency of gold implies there is nothing hidden, no opacity between creature and Creator.</p>',

    "19": '<p><strong>hoi themelioi tou teichous tēs poleōs panti lithō timiō kekosmēmenoi</strong>: the twelve foundations adorned with precious stones. The list (jasper, sapphire, agate, emerald, onyx, ruby, chrysolite, beryl, topaz, chrysoprase, jacinth, amethyst) parallels but does not perfectly match the high priestly breastplate of Exod 28:17-20 — eight of the twelve correspond. The LXX order differs from the MT. The connection to the breastplate is deliberate: the high priest bore the names of the twelve tribes over his heart as he entered the sanctuary; the new Jerusalem\'s foundations bear the apostles\' names. The priestly imagery is transferred from one individual mediator to the entire apostolic foundation of the city.</p>',

    "20": '<p><strong>ho pemptos sardonyx ho hektos sardion ho hebdomos chrysolithos ho ogdoos bēryllos ho ennatos topazion ho dekatos chrysoprason ho hendekatos hyakinthos ho dōdekatos amethystos</strong>: the list of the final eight foundation stones. Ancient gemstone terminology is imprecise and identification of the exact minerals is uncertain — Greek and Hebrew stone names do not map neatly onto modern mineralogical categories. What is clear is the visual effect: the twelve foundations are a spectrum of color, light, and brilliance. The cumulative image is not a building inventory but a vision of transcendent beauty — the city adorned as a bride (v. 2) made architectural.</p>',

    "21": '<p><strong>kai hoi dōdeka pylōnes dōdeka margaritai, heis hekastos tōn pylōnōn ēn ex henos margaritou</strong>: each gate a single pearl. A pearl of sufficient size to serve as a city gate is obviously beyond natural possibility — the image functions as a superlative of purity and singular beauty. Pearls in the ancient world were considered the most precious of gems (Matt 13:46 uses the single great pearl as the image for the kingdom). Each gate is irreducibly one thing — unified, perfect, unbroken.</p><p><strong>kai hē plateia tēs poleōs chrysos katharos hōs hyalos diaphanes</strong>: the main street of pure gold transparent as glass. <em>Plateia</em> (broad way, main street, public space) is singular — the whole city has one street, or the entire ground level is this open transparent space. The transparency motif recurs: nothing opaque, nothing hidden, divine light permeating the material structure of the city itself.</p>',

    "22": '<p><strong>kai naon ouk eidon en autē</strong>: "I did not see a temple in it." The deliberate absence. The temple was the locus of divine presence in the old order — the place where heaven and earth intersected, where priests mediated access to God, where sacrifice was offered. Its absence is not a loss but a fulfillment: there is no need for a mediated presence when the presence is direct and total.</p><p><strong>ho gar Kyrios ho Theos ho Pantokrator naos autēs estin kai to Arnion</strong>: the Lord God Almighty and the Lamb are its temple. God and the Lamb together constitute the temple — singular — the co-divine presence that fills the new Jerusalem without boundary or mediation. This fulfills the trajectory from Exod 25:8 (let them make me a sanctuary that I may dwell among them) through John 2:19-21 (the temple he spoke of was his body) to Rev 21:3 (the dwelling of God is with people). The tabernacle, the temple, the incarnate Christ, and the new Jerusalem form one continuous line of divine-presence theology.</p>',

    "23": '<p><strong>kai hē polis ou chreian echei tou hēliou oude tēs selēnēs hina phainōsin autē</strong>: "the city has no need of the sun or moon to shine on it." This fulfills Isa 60:19-20 verbatim in sense: "No longer will you have the sun for light by day ... for the LORD will be your everlasting light." The sun and moon are part of the old creation\'s luminous order; in the new creation the divine glory replaces them.</p><p><strong>hē gar doxa tou theou ephōtisen autēn kai ho lychnos autēs to Arnion</strong>: the glory (<em>doxa</em>, Shekinah) of God is the city\'s light source, and the Lamb is its <em>lychnos</em> (lamp, luminous body). The same Christ who declared "I am the light of the world" (John 8:12; 9:5) is the lamp of the new Jerusalem. The divine glory and the Lamb\'s lamp are distinguished but function together — the Trinitarian shape of the new creation\'s illumination.</p>',

    "24": '<p><strong>kai peripatēsousin ta ethnē dia tou phōtos autēs</strong>: "the nations will walk by its light." The inclusion of <em>ta ethnē</em> (the nations/Gentiles) as permanent inhabitants and participants fulfills the long prophetic vision of Isa 60:3 (nations shall come to your light) and Zech 14:16 (all nations will go up year after year to worship the King). This is not Gentile conversion to Israel\'s religion but the eschatological unity of all peoples in the new Jerusalem — the culmination of the Abrahamic promise that all nations would be blessed (Gen 12:3).</p><p><strong>kai hoi basileis tēs gēs pherousin tēn doxan autōn eis autēn</strong>: the kings of the earth bring their <em>doxa</em> (glory, splendor) into the city. These are the same <em>basileis tēs gēs</em> who throughout Revelation opposed God and the Lamb (6:15; 17:2; 18:3). Their tribute in the new creation reverses their rebellion in the old order: those who resisted now bring honor freely. This is not universalism but the comprehensive sovereignty of the new creation encompassing even those who opposed it.</p>',

    "25": '<p><strong>kai hoi pylōnes autēs ou mē kleisthōsin hēmeras</strong>: "its gates shall never be shut by day" — the gates of the ancient city were shut at night for security. The new Jerusalem\'s gates never close because there is no threat, no night, no hostile force that could require them. Open gates signal total security: the city is not fortified against enemies because there are none. The promise fulfills Isa 60:11 (your gates shall be open continually, day and night they shall not be shut).</p><p><strong>nyx gar ouk estai ekei</strong>: "for there will be no night there." Night in Revelation is associated with darkness, hiddenness, and the activities of evil (1 Thess 5:5-7; John 3:19). Its abolition in the new Jerusalem (repeated in 22:5) is not merely a meteorological observation but a theological one: the conditions for evil, deception, and darkness no longer obtain.</p>',

    "26": '<p><strong>kai oisousin tēn doxan kai tēn timēn tōn ethnōn eis autēn</strong>: "they will bring the glory and honor of the nations into it." <em>Doxa kai timē</em> (glory and honor) — the paired terms used of God\'s worthiness in doxological contexts (4:9, 11; 5:12-13). That the nations bring <em>doxa</em> implies that what the nations had — their cultures, achievements, excellences — is not destroyed in the new creation but transformed and offered. The new Jerusalem receives the best of human history, transfigured and consecrated.</p>',

    "27": '<p><strong>kai ou mē eiselthē eis autēn pan koinon kai [ho] poiōn bdelygma kai pseudos</strong>: the double negative <em>ou mē</em> with the aorist subjunctive is emphatic prohibition — nothing common/impure shall enter. <em>Koinon</em> (common, defiling — the cultic term for what violates ritual purity; Acts 10:14-15 uses it for what Peter considered unclean). <em>Bdelygma</em> (abomination) echoes the "abomination of desolation" (Dan 9:27; 11:31; Mark 13:14) — here permanently excluded rather than temporarily installed in the temple.</p><p><strong>ei mē hoi gegrammenoi en tō bibliō tēs zōēs tou Arniou</strong>: "except those written in the Lamb\'s book of life." The only qualification for entry is name-inscription by the Lamb — not ethnic identity, moral achievement, or ritual status, but the Lamb\'s own record. The <em>biblion tēs zōēs</em> (book of life) appears throughout Revelation (3:5; 13:8; 17:8; 20:12, 15) as the definitive eschatological register. It belongs to the Lamb: he holds the criterion of entry.</p>'
  },
  "22": {
    "1": '<p><strong>kai edeixen moi potamon hydatos zōēs lampron hōs krystallon ekporeuomenon ek tou thronou tou theou kai tou Arniou</strong>: the river of the water of life, bright as crystal, proceeding from the throne of God <em>and</em> of the Lamb. The singular throne shared by God and the Lamb (also v. 3) carries Christological weight: Revelation insists on co-enthronement, not adjacent thrones. The river\'s source is the co-divine throne, echoing Ezek 47:1-12 (the temple-river flowing east bringing life) and Zech 14:8 (living waters flowing from Jerusalem). In Ezekiel\'s vision the river flows from the temple; here the throne replaces the temple (21:22) as the source of living water.</p>',

    "2": '<p><strong>en mesō tēs plateias autēs kai tou potamou enteuthen kai ekeithen xylon zōēs poioun karpous dōdeka kata mēna</strong>: the tree of life (<em>xylon zōēs</em>) standing on both sides of the river, bearing twelve fruits, one each month — monthly fruit, not seasonal. The perpetual and varied fruitfulness signals inexhaustible provision. <em>Xylon zōēs</em> (tree of life) is the Genesis tree (Gen 2:9; 3:22-24) from which humanity was barred after the Fall; the new creation restores unlimited access. The twelve fruits monthly is a temporal abundance that no natural growing season could sustain.</p><p><strong>kai ta phyla tou xylou eis therapeia tōn ethnōn</strong>: "and the leaves of the tree for the healing of the nations." <em>Therapeia</em> (healing, therapy) applied to the nations — the tree\'s leaves heal at a national, not merely individual, scale. This picks up Ezek 47:12 (fruit for food and leaves for medicine/healing). The healing of the nations implies some form of ongoing restoration in the new creation, though the precise nature of this healing in an already-perfect world resists precise specification.</p>',

    "3": '<p><strong>kai pan katathema ouk estai eti</strong>: "and no curse will be there any more." <em>Katathema</em> (curse, accursed thing) — the curse of Gen 3:17-19 (cursed is the ground because of you) is the source of all human suffering, toil, death, and the frustration of creation (Rom 8:20-22). Its abolition is the reversal of the Fall\'s cosmic consequences. Paul\'s statement that "Christ became a curse for us" (Gal 3:13) is the atonement event that makes this eschatological abolition possible.</p><p><strong>kai ho thronos tou theou kai tou Arniou en autē estai</strong>: the throne of God <em>and</em> the Lamb — singular throne, dual subjects. Grammatically striking: two persons, one throne. The Lamb\'s co-enthronement with the Father in the new Jerusalem is the final statement of Revelation\'s high Christology. <em>Hoi douloi autou latreusousin autō</em>: his servants will <em>latreuō</em> him — the verb specifically used for religious service and worship (Heb 12:28; Luke 2:37). The new creation is characterized by unmediated, ceaseless worship of the co-enthroned God and Lamb.</p>',

    "4": '<p><strong>kai opsontai to prosōpon autou</strong>: "they will see his face." The beatific vision — direct, unmediated, face-to-face knowledge of God. In the OT, seeing God\'s face was dangerous or impossible (Exod 33:20: "you cannot see my face, for no one may see me and live"; Gen 32:30: "I have seen God face to face and yet my life has been spared"). The new creation removes this barrier: the redeemed see the face of God directly because the old order of divine hiddenness has given way to full presence. This is the ultimate fulfillment of the priestly blessing (Num 6:26: "the LORD make his face shine on you").</p><p><strong>kai to onoma autou epi tōn metōpōn autōn</strong>: his name on their foreheads — the opposite of the mark of the beast on the foreheads of his worshippers (13:16-17). The sealed 144,000 already bore God\'s seal on their foreheads (7:3; 14:1). In the new Jerusalem this identity-marking is permanent and visible: they belong to God and the Lamb, identified by name as his own. The name on the forehead is ownership, identity, and protection all at once.</p>',

    "5": '<p><strong>kai nyx ouk estai eti kai ou chreian echousin phōtos lychnou kai phōtos hēliou hoti Kyrios ho Theos phōtisei ep autous</strong>: no night, no lamp, no sun — the Lord God will shine on (<em>phōtisei</em>, illuminate) them directly. <em>Phōtizō</em> (to illuminate) is used of God\'s eschatological light (Isa 60:19 LXX; Rev 21:23). The abolition of created light sources is not loss but supersession: what the sun and lamp did partially and temporarily, God does fully and permanently.</p><p><strong>kai basileusousin eis tous aiōnas tōn aiōnōn</strong>: "they will reign for ever and ever." The saints\' reign with Christ (20:6) is here made permanent and universal. Dan 7:18, 22, 27 promised that the holy ones of the Most High would receive the kingdom forever; Rev 22:5 declares this fulfilled. The redeemed do not merely dwell in the new creation but <em>reign</em> in it — the restoration of the royal image-bearing vocation of Gen 1:26-28, now fully realized.</p>',

    "6": '<p><strong>hoi logoi pistoi kai alēthinoi</strong>: the authentication formula (also 19:9; 21:5). The repetition at the book\'s conclusion brackets the entire vision with divine guarantee: what was pledged at the outset of the epilogue is confirmed at its close. <em>Kyrios ho theos tōn pneumatōn tōn prophētōn</em> (the Lord, the God of the spirits of the prophets): a distinctive title found only here in Revelation, identifying God specifically as the inspirer of prophecy. The one who sent his angel to show the prophets what must soon take place is the same God who has been speaking through the prophets all along — continuity between OT prophecy and Revelation\'s vision asserted in the divine title itself.</p>',

    "7": '<p><strong>idou erchomai tachy</strong>: "Behold I am coming quickly/soon." The first of three <em>erchomai tachy</em> sayings in the chapter (vv. 7, 12, 20) — a rhetorical triad building to the final exchange with the community in v. 20. <em>Tachy</em> (quickly, soon) has been the eschatological urgency marker throughout Revelation (1:1; 2:16; 3:11; 22:7, 12, 20). The imminent return is not a mistaken prediction but an eschatological stance: the church lives under the horizon of the returning Lord.</p><p><strong>makarios ho tērōn tous logous tēs prophēteias tou bibliou toutou</strong>: the seventh and final beatitude in Revelation (see 1:3; 14:13; 16:15; 19:9; 20:6; 22:14). <em>Tērōn</em> (keeping, guarding, observing) — present participle: ongoing keeping, not a single act. The beatitude at the book\'s close mirrors 1:3 (blessed is the one who reads and hears and keeps these words), forming a frame around the entire Apocalypse.</p>',

    "8": '<p><strong>kagō Iōannēs ho akouōn kai blepōn tauta</strong>: the Seer\'s self-identification — "I, John, the one hearing and seeing these things." The emphasis on hearing and seeing is Revelation\'s epistemological claim: this is received revelation (heard and seen), not theological speculation. The same identification occurs at 1:9 where John situates himself in the persecuted community. The repetition here at the book\'s end confirms the same human witness for both the beginning and the conclusion of the vision.</p><p><strong>kai hote ēkousa kai eidon, epesa proskunēsai emprosthen tōn podōn tou angelou tou deiknuontos moi tauta</strong>: John falls to worship before the revealing angel — the same error as 19:10 (where the angel gives the same rebuke). The repetition is not careless; it illustrates the persistent human tendency to misdirect worship toward the mediator of revelation rather than the source. The correct response to overwhelming revelatory experience is not prostration before the messenger.</p>',

    "9": '<p><strong>kai legei moi Hora mē syndoulos sou gar eimi kai tōn adelphōn sou tōn prophētōn kai tōn tērountōn tous logous tou bibliou toutou tō theō proskunēson</strong>: "See that you do not do this! I am a fellow servant with you and your brothers the prophets and with those who keep the words of this scroll. Worship God!" The angel\'s self-description as <em>syndoulos</em> (fellow-servant, co-slave) places him in the same category as John, the prophets, and all who keep the book\'s words. The hierarchy of worship is absolute: <em>tō theō proskunēson</em> (worship God [alone]) — the angel enforces monotheistic worship by refusing it for himself. <em>Proskyneō</em> (worship, bow before) is the term Revelation reserves for God and the Lamb (4:10; 5:14; 7:11; 11:16; 19:4, 10; 22:8-9).</p>',

    "10": '<p><strong>Mē sphragisēs tous logous tēs prophēteias tou bibliou toutou</strong>: "Do not seal up the words of the prophecy of this scroll." This is the direct inversion of Dan 12:4 (<em>sphragison to biblion</em>, "seal the book, Daniel, until the time of the end"). Daniel was told to seal because the fulfillment was distant; John is told not to seal because <em>ho kairos engys</em> (the time is near). The unsealing of John\'s prophetic scroll signals that the Danielic "time of the end" has arrived in and through Christ — the seals of history are being opened (ch. 6) rather than imposed. The eschatological "near" is the church\'s permanent posture of readiness, not a chronological prediction about a specific date.</p>',

    "11": '<p><strong>ho adikōn adikēsatō eti, kai ho rhyparos rhyparasthētō eti, kai ho dikaios dikaiosynēn poiēsatō eti, kai ho hagios hagiasthētō eti</strong>: the fourfold declaration of fixity — let the unjust continue unjust, the defiled continue defiled, the righteous continue righteous, the holy continue holy. This is not permission for sin but an announcement of eschatological ultimacy: at the threshold of judgment, moral states are confirmed. The call to repentance is complete; the time for reversals is over. The hardened will not be transformed by more time; the holy will not be endangered by the end\'s arrival. The final state of each is the continuation of their present direction, accelerated to completion.</p>',

    "12": '<p><strong>idou erchomai tachy kai ho misthos mou met emou apodounai hekastō hōs to ergon estin autou</strong>: the second <em>erchomai tachy</em> (v. 7, 12, 20). Here paired with the judgment: <em>ho misthos mou met emou</em> (my reward/wages are with me) — the eschatological recompense brought by the returning Lord. <em>Apodounai hekastō hōs to ergon autou</em> (to render to each according to their work) cites the standard OT judgment formula (Ps 62:12; Prov 24:12; Isa 40:10) applied to Christ: the one who comes is also the one who judges. This links the parousia and the judgment as one event, not two sequential stages.</p>',

    "13": '<p><strong>ego to Alpha kai to Omega, ho prōtos kai ho eschatos, hē archē kai to telos</strong>: the threefold divine identity formula applied to Christ — the fullest divine self-identification in the NT. Each pair captures a different aspect: Alpha/Omega (the entire alphabet of reality, from first to last letter), First/Last (temporal priority and finality — echoing YHWH\'s self-identification in Isa 44:6 and 48:12), Beginning/End (<em>archē kai telos</em> — ontological primacy and consummation). In 1:8 the Alpha-Omega title is applied to "the Lord God Almighty" (the Father); here all three pairs are applied to Christ. Revelation\'s Christological high point: the crucified and risen Jesus is identified with YHWH\'s own divine self-designation.</p>',

    "14": '<p><strong>makarioi hoi plynnontes tas stolas autōn</strong>: "Blessed are those who wash their robes." The sixth beatitude in Revelation. An important textual variant: some MSS (including Codex A and the Textus Receptus) read <em>poiountes tas entolas autou</em> (doing his commandments); the UBS/NA28 critical text prefers <em>plynnontes tas stolas autōn</em> (washing their robes), supported by Sinaiticus and Alexandrinus. The robes-washing image echoes 7:14 (they washed their robes and made them white in the blood of the Lamb) — the passive work of atonement rather than active commandment-keeping. Both readings convey holiness, but the robes-washing variant locates holiness in Christ\'s atoning work.</p><p><strong>hina estai hē exousia autōn epi to xylon tēs zōēs kai tois pylōsin eiselthōsin eis tēn polin</strong>: <em>exousia</em> (authority, right, legal standing) to the tree of life and entry through the gates. The legal term <em>exousia</em> (not merely <em>dynamis</em> = power) signals that the right to enter is forensic: it is granted, not seized. The tree of life access denied in Gen 3:24 is restored by the Lamb\'s atoning work that makes the robe-washers clean.</p>',

    "15": '<p><strong>exō hoi kynes kai hoi pharmakoi kai hoi pornoi kai hoi phoneis kai hoi eidōlolatrai kai pas philōn kai poiōn pseudos</strong>: outside the city are five categories plus "all who love and practice falsehood." <em>Kynes</em> (dogs): in Jewish purity discourse, dogs were ritually unclean animals associated with those who returned to their vomit (2 Pet 2:22; Prov 26:11) and used metaphorically for those who had abandoned the faith or remained outside the covenant community. Phil 3:2 uses <em>kynas</em> for the circumcision party; here it is the final-state category for those outside the new Jerusalem. The list mirrors 21:8. <em>Pas philōn kai poiōn pseudos</em> (everyone who loves and makes falsehood) — the participial construction indicates characteristic love-of-lying, not occasional lapse; the disposition, not the act alone.</p>',

    "16": '<p><strong>ego Iēsous epempsa ton angelon mou martyrēsai hymin tauta epi tais ekklēsiais</strong>: Jesus identifies himself as the sender of the angel — the one who commissioned the entire revelation. <em>Hymin</em> (to you, plural) addresses the seven churches collectively. <em>Martyrēsai</em> (to testify, bear witness) — the entire Apocalypse is framed as divine testimony, not human speculation.</p><p><strong>ego eimi hē rhiza kai to genos David ho astēr ho lampros ho prōinos</strong>: two messianic identifications. <em>Hē rhiza kai to genos David</em> (the root and the offspring of David) — root = David\'s ancestor (Isa 11:10: the root of Jesse as the one the nations seek), offspring = David\'s descendant (Isa 11:1: a shoot from the stump of Jesse). Jesus is both ancestor and descendant: as divine Son he is the source of the Davidic line; as incarnate Son he is David\'s descendant. The title in Rev 5:5 (<em>rhiza David</em>) here expanded. <em>Ho astēr ho lampros ho prōinos</em> (the bright morning star): the morning star (Venus) appears just before dawn — a herald of the coming day. Num 24:17 (a star shall come out of Jacob) is the messianic star prophecy; here Christ applies it to himself as the harbinger of the eschatological dawn.</p>',

    "17": '<p><strong>kai to Pneuma kai hē Nymphē legousin Erchou</strong>: "The Spirit and the Bride say, Come!" Two voices united in the eschatological invitation: the Spirit (divine, the one who has been speaking to the churches throughout chs. 2–3: "what the Spirit says to the churches") and the Bride (the church, the new Jerusalem of ch. 21). Their unified cry <em>Erchou</em> (Come!) is addressed to Christ, the returning Lord.</p><p><strong>kai ho akouōn eipatō Erchou, kai ho dipsōn erchasthō, ho thelōn labetō hydōr zōēs dōrean</strong>: the congregation joins (let the one who hears say Come), then the invitation opens to all who are thirsty (let the thirsty come, let the willing take the water of life as a gift). The final invitation of the Bible: <em>dōrean</em> (freely, as gift — same word as 21:6). This is the closing of John 7:37-38 (Jesus on the last day of the feast: "If anyone thirsts, let him come to me and drink") and Isa 55:1 (come to the waters, all you who are thirsty) extended to the entire canon\'s close.</p>',

    "18": '<p><strong>martyrō egō panti tō akouonti tous logous tēs prophēteias tou bibliou toutou</strong>: <em>martyrō</em> (I testify, I solemnly warn — the word of authoritative witness). The warning against adding or subtracting echoes the Deuteronomy formula (Deut 4:2: "You shall not add to the word that I command you, nor take from it"; Deut 12:32) and the same formula applied to the book of Proverbs (Prov 30:6). Revelation here asserts canonical finality: this prophetic scroll is closed, complete, not to be supplemented or reduced. The gravity of the warning (<em>prosthēsei ho theos ep auton tas plēgas</em> — God will add to him the plagues written in this book) claims Torah-level authority for the Apocalypse.</p>',

    "19": '<p><strong>kai ean tis aphelē apo tōn logōn tou bibliou tēs prophēteias tautēs, aphelei ho theos to meros autou apo tou xylou tēs zōēs kai ek tēs poleōs tēs hagias</strong>: the negative counterpart — taking away from the book results in losing one\'s share in the tree of life and the holy city. <em>Meros</em> (share, portion) of the tree of life is the inheritance language: the subtracter loses their inheritance in the new Jerusalem. The symmetry of addition and subtraction penalties mirrors the canonical seriousness: the integrity of the prophetic text is coextensive with the integrity of one\'s standing in the new creation. Textual variant: some MSS read <em>xylou zōēs</em> (tree of life) vs. <em>bibliou zōēs</em> (book of life); the former fits the new Jerusalem imagery of 22:2 and 22:14 better.</p>',

    "21": '<p><strong>hē charis tou Kyriou Iēsou meta pantōn</strong>: "The grace of the Lord Jesus be with all." The Pauline epistolary benediction (cf. 1 Cor 16:23; Gal 6:18; Phil 4:23; 1 Thess 5:28; 2 Thess 3:18; Philem 25) applied to the Apocalypse — fitting, since Revelation is framed as a letter to the seven churches (1:4). <em>Charis</em> (grace) is the final word of the NT canon in the manuscript tradition. The entire Bible ends with grace: not command, not judgment, not prediction, but the free gift of God in Christ extending to "all." <em>Pantōn</em> (all) without qualifier — the grace of the Lord Jesus is offered without restriction.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'revelation')
    merge_comm(existing, REVELATION)
    save_comm('mkt-original', 'revelation', existing)
    print('Revelation 21–22 mkt-original written.')

if __name__ == '__main__':
    main()
